SELECT total_co2_emissions
FROM co2_emissions
WHERE sector_id = 1 AND year = 2020;

SELECT SUM(total_co2_emissions) AS total_emissions
FROM co2_emissions
WHERE sector_id = 1 AND year = 2020;

SELECT SUM(total_co2_emissions) AS total_co2_emissions_2020
FROM co2_emissions
WHERE year = 2020;

SELECT total_co2_emissions
   FROM co2_emissions
   WHERE year = 2020;

SELECT year, MAX(total_co2_emissions_mt) AS highest_total_co2_emissions
FROM co2_emissions
WHERE year = 2022;

SELECT total_co2_emissions
FROM co2_emissions
WHERE sector_id = (SELECT sector_id FROM sectors WHERE sector_name = 'Transportation') AND year = 2020;

SELECT SUM(transportation) AS total_transportation_emissions
FROM co2_emissions
WHERE sector_id = (SELECT sector_id FROM sectors WHERE sector_name = 'Transportation');

SELECT sector_name, description
FROM sectors
ORDER BY sector_name ASC;
